org.machanism.machai.ai.provider.Genai provider = new org.machanism.machai.ai.provider.openai.OpenAIProvider();
org.machanism.macha.core.commons.configurator.Configurator conf = null;
provider.init("gpt-4o-mini", conf);

provider.instructions("You are a helpful assistant.");
provider.prompt("Hello!");
java.lang.String response = provider.perform();

org.machanism.machai.ai.provider.Genai provider = org.machanism.machai.ai.manager.GenaiProviderManager.getProvider("OpenAI:gpt-4o-mini", conf);
org.machanism.machai.ai.tools.FunctionToolsLoader loader = new org.machanism.machai.ai.tools.FunctionToolsLoader();
loader.applyTools(provider, com.example.MyApplication.class);

org.machanism.macha.core.commons.configurator.Configurator conf = null;
org.machanism.machai.ai.provider.Genai provider = org.machanism.machai.ai.manager.GenaiProviderManager.getProvider("OpenAI:gpt-4o-mini", conf);
provider.instructions("You are a helpful assistant.");
provider.prompt("Summarize this repository.");
java.lang.String answer = provider.perform();
provider.clear();

org.machanism.macha.core.commons.configurator.Configurator conf = null;
org.machanism.machai.ai.provider.EmbeddingProvider provider = org.machanism.machai.ai.manager.GenaiProviderManager.getEmbeddingProvider("OpenAI:text-embedding-3-small", conf);
java.util.List<java.lang.Double> vector = provider.embedding("A document to index for semantic search", 384L);

org.machanism.machai.ai.provider.Genai provider = org.machanism.machai.ai.manager.GenaiProviderManager.getProvider("OpenAI:gpt-4o-mini", conf);
org.machanism.machai.ai.tools.FunctionToolsLoader loader = new org.machanism.machai.ai.tools.FunctionToolsLoader();
loader.applyTools(provider, com.example.MyApplication.class);
provider.prompt("Use the available tools to inspect the project and summarize findings.");
java.lang.String result = provider.perform();
